import React from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';

export default function Navbar() {
  const navigate = useNavigate();
  const location = useLocation();
  const token = localStorage.getItem('token');
  const logout = () => {
    localStorage.removeItem('token');
    navigate('/login');
  };

  const linkBase = 'text-sm px-4 py-2 rounded-xl transition-all duration-200 font-medium';

  return (
    <nav className="sticky top-0 z-40 backdrop-blur-xl bg-black/10 border-b border-white/10">
      <div className="max-w-6xl mx-auto px-6 py-4 flex items-center justify-between">
        <Link to="/" className="text-2xl font-bold tracking-tight">
          <span className="bg-gradient-to-r from-blue-400 via-purple-400 to-pink-400 bg-clip-text text-transparent">
            Task Manager
          </span>
        </Link>
        
        <div className="flex items-center gap-3">
          {token && (
            <Link
              to="/tasks/new"
              className={`${linkBase} bg-gradient-to-r from-blue-500 to-purple-600 text-white shadow-lg hover:from-blue-600 hover:to-purple-700 transform hover:scale-105`}
            >
              + Add Task
            </Link>
          )}
          
          {token ? (
            <button
              onClick={logout}
              className={`${linkBase} bg-white/10 border border-white/20 text-white hover:bg-white/20 backdrop-blur-sm`}
            >
              Logout
            </button>
          ) : (
            <>
              <Link
                to="/login"
                className={`${linkBase} ${location.pathname === '/login' ? 'bg-white/20 text-white' : 'bg-white/10 border border-white/20 text-white hover:bg-white/20'} backdrop-blur-sm`}
              >
                Login
              </Link>
              <Link
                to="/register"
                className={`${linkBase} bg-gradient-to-r from-purple-500 to-pink-500 text-white shadow-lg hover:from-purple-600 hover:to-pink-600 transform hover:scale-105`}
              >
                Register
              </Link>
            </>
          )}
        </div>
      </div>
    </nav>
  );
}
